# String utility module

def reverse(s: str) -> str:
    result: str = ""
    for c in s:
        result = str(c) + result
    return result

def is_palindrome(s: str) -> bool:
    return s == reverse(s)

def word_count(text: str) -> int:
    words: list[str] = text.split(" ")
    return len(words)

