# Math utility module

def factorial(n: int) -> int:
    if n <= 1:
        return 1
    return n * factorial(n - 1)

@static
CACHE: dict[int, int] = {}

def fibonacci(n: int) -> int:
    if n in CACHE:
        return CACHE[n]
    if n <= 1:
        result: int = n
    else:
        result: int = fibonacci(n - 1) + fibonacci(n - 2)
    CACHE[n] = result
    return result

def is_prime(n: int) -> bool:
    if n <= 1:
        return False
    if n <= 3:
        return True
    if n % 2 == 0:
        return False
    i: int = 3
    while i * i <= n:
        if n % i == 0:
            return False
        i += 2
    return True
